export function matchExtendedKnowledge(question: string): BookKnowledgeCategory[] {
  const results: BookKnowledgeCategory[] = [];
  for (const [keywords, categories] of Object.entries(KEYWORD_MAP)) {
    try {
      const regex = new RegExp(keywords, 'i');
      if (regex.test(question)) {
        for (const cat of categories) {
          const entry = EXTENDED_BOOK_KNOWLEDGE[cat];
          if (entry) {
            results.push(entry);
          }
        }
      }
    } catch {
      // Skip invalid regex patterns
    }
  }
  return results;
}
